import { describe, it, expect, vi } from "vitest";
import { readFileSync, writeFileSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join, dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { attachKeywords, contentHashOf, readSidecar, SCHEMA_VERSION } from "./keywords.mjs";

const HERE = dirname(fileURLToPath(import.meta.url));
// site/scripts/lib/keywords.test.mjs -> site/src/catalog.json (generated by
// the `pretest` -> `npm run index` hook before this suite runs).
const CATALOG_PATH = resolve(HERE, "../../src/catalog.json");

function baseArtifact(overrides = {}) {
  return {
    id: "test-plugin/skill/example",
    type: "skill",
    displayName: "Example Skill",
    description: "An example skill for testing.",
    body: "# Example\n\nSome body content.",
    tags: ["example", "testing"],
    ...overrides,
  };
}

describe("contentHashOf", () => {
  it("is stable for identical input and changes when displayName/description/body change", () => {
    const hash1 = contentHashOf(baseArtifact());
    const hash2 = contentHashOf(baseArtifact());
    expect(hash1).toBe(hash2);
    expect(hash1).toMatch(/^sha256:[0-9a-f]{64}$/);

    expect(contentHashOf(baseArtifact({ body: "a different body" }))).not.toBe(hash1);
    expect(contentHashOf(baseArtifact({ description: "a different description" }))).not.toBe(hash1);
    expect(contentHashOf(baseArtifact({ displayName: "Different Name" }))).not.toBe(hash1);
  });

  it("EXCLUDES updatedAt/gitDate — those change on every commit and must not affect the hash", () => {
    const withOldDate = contentHashOf(baseArtifact({ updatedAt: "2020-01-01T00:00:00.000Z" }));
    const withNewDate = contentHashOf(baseArtifact({ updatedAt: "2026-07-14T00:00:00.000Z", gitDate: "2026-07-14" }));
    expect(withOldDate).toBe(withNewDate);
  });

  it("EXCLUDES tags — tags and keywords are independent", () => {
    const a = contentHashOf(baseArtifact({ tags: ["a"] }));
    const b = contentHashOf(baseArtifact({ tags: ["b", "c", "d"] }));
    expect(a).toBe(b);
  });

  it("does not throw on an empty body (E-9)", () => {
    expect(() => contentHashOf(baseArtifact({ body: "" }))).not.toThrow();
    expect(() => contentHashOf({ displayName: "X", description: "Y" })).not.toThrow();
  });

  it("is line-ending agnostic: CRLF and LF renderings of the SAME content hash identically", () => {
    // Regression for the cross-platform hash-drift bug: source `.md` files
    // checkout as CRLF on Windows (core.autocrlf) and LF on Linux CI, so a
    // content hash that doesn't normalize line endings produces two
    // different hashes for the exact same logical content.
    const lfArtifact = baseArtifact({
      displayName: "Example\nSkill",
      description: "An example skill\nfor testing.",
      body: "# Example\n\nSome body content.\nSecond line.",
    });
    const crlfArtifact = baseArtifact({
      displayName: "Example\r\nSkill",
      description: "An example skill\r\nfor testing.",
      body: "# Example\r\n\r\nSome body content.\r\nSecond line.",
    });
    expect(contentHashOf(crlfArtifact)).toBe(contentHashOf(lfArtifact));
  });
});

describe("attachKeywords", () => {
  it("attaches the sidecar's keywords and reports no warnings when the hash matches", () => {
    const artifact = baseArtifact();
    const sidecar = {
      schemaVersion: SCHEMA_VERSION,
      artifacts: {
        [artifact.id]: {
          keywords: ["synonym one", "problem phrase"],
          contentHash: contentHashOf(artifact),
        },
      },
    };
    const { artifacts, warnings } = attachKeywords([artifact], sidecar);
    expect(warnings).toEqual([]);
    expect(artifacts[0].keywords).toEqual(["synonym one", "problem phrase"]);
  });

  it("warns and NAMES the artifact when the stored contentHash has drifted, without throwing (AC-20)", () => {
    const artifact = baseArtifact();
    const sidecar = {
      artifacts: {
        [artifact.id]: {
          keywords: ["stale keyword"],
          contentHash: "sha256:not-the-real-hash",
        },
      },
    };
    let result;
    expect(() => {
      result = attachKeywords([artifact], sidecar);
    }).not.toThrow();
    expect(result.warnings).toHaveLength(1);
    expect(result.warnings[0]).toContain(artifact.id);
    // Keywords are still attached even when stale — a warning must never fail the build.
    expect(result.artifacts[0].keywords).toEqual(["stale keyword"]);
  });

  it("warns (does not throw) when an artifact has no sidecar entry at all", () => {
    const artifact = baseArtifact({ id: "unlisted/skill/example" });
    const sidecar = { artifacts: {} };
    let result;
    expect(() => {
      result = attachKeywords([artifact], sidecar);
    }).not.toThrow();
    expect(result.warnings).toHaveLength(1);
    expect(result.warnings[0]).toContain(artifact.id);
    expect(result.artifacts[0].keywords).toEqual([]);
  });

  it("dedupes keywords that duplicate a tag or a displayName token (E-10)", () => {
    const artifact = baseArtifact({
      displayName: "Drizzle ORM Patterns",
      tags: ["drizzle", "orm"],
    });
    const sidecar = {
      artifacts: {
        [artifact.id]: {
          keywords: ["orm", "drizzle", "sql toolkit", "sql toolkit", "query builder"],
          contentHash: contentHashOf(artifact),
        },
      },
    };
    const { artifacts } = attachKeywords([artifact], sidecar);
    // "orm" duplicates a tag, "drizzle" duplicates a tag AND a displayName
    // token, the repeated "sql toolkit" is a plain duplicate — all stripped.
    expect(artifacts[0].keywords).toEqual(["sql toolkit", "query builder"]);
  });

  it("never lets the dedupe guard empty an array that started non-empty (AC-9 guard)", () => {
    const artifact = baseArtifact({ displayName: "Example", tags: ["example"] });
    const sidecar = {
      artifacts: {
        [artifact.id]: {
          // every keyword duplicates the tag/displayName token
          keywords: ["example"],
          contentHash: contentHashOf(artifact),
        },
      },
    };
    const { artifacts } = attachKeywords([artifact], sidecar);
    expect(artifacts[0].keywords.length).toBeGreaterThan(0);
  });
});

describe("readSidecar", () => {
  it("tolerates a missing file: warns once and returns an empty artifact map", () => {
    const warnSpy = vi.spyOn(console, "warn").mockImplementation(() => {});
    const sidecar = readSidecar(resolve(HERE, "this-file-does-not-exist.json"));
    expect(sidecar.artifacts).toEqual({});
    expect(warnSpy).toHaveBeenCalledTimes(1);
    warnSpy.mockRestore();
  });

  it("tolerates malformed JSON: warns, does not throw, and returns an empty artifact map", () => {
    const tmpFile = join(tmpdir(), `keywords-malformed-${Date.now()}-${Math.random().toString(36).slice(2)}.json`);
    writeFileSync(tmpFile, "{ this is not valid json");
    try {
      const warnSpy = vi.spyOn(console, "warn").mockImplementation(() => {});
      let sidecar;
      expect(() => {
        sidecar = readSidecar(tmpFile);
      }).not.toThrow();
      expect(sidecar.artifacts).toEqual({});
      expect(warnSpy).toHaveBeenCalledTimes(1);
      warnSpy.mockRestore();
    } finally {
      rmSync(tmpFile, { force: true });
    }
  });
});

describe("AC-9: real sidecar coverage", () => {
  it("every artifact in the real generated catalog has at least one keyword", () => {
    const catalog = JSON.parse(readFileSync(CATALOG_PATH, "utf8"));
    expect(catalog.artifacts.length).toBeGreaterThan(0);
    const withoutKeywords = catalog.artifacts.filter((a) => !Array.isArray(a.keywords) || a.keywords.length === 0);
    expect(withoutKeywords.map((a) => a.id)).toEqual([]);
  });
});
